#include<iostream>
#include<algorithm>
using namespace std;

class Solution {
public:
    void insert(int* arr, int n, int val) {
        arr[n] = val;
        for (int i = n-1; i >= 0; i--) {
            if (arr[i] > arr[(i-1)/2]) {
                swap(arr[i], arr[(i-1)/2]);
                i = (i-1)/2;
            }
        }
    }
};

int main() {
    int arr[] = {4, 10, 3, 8, 9, 1};
    int n = sizeof(arr)/sizeof(arr[0]);
    int val1 = 7;
    int val2 = 10;
    Solution s;
    s.insert(arr, n, val1);
    s.insert(arr, n, val2);
    cout << "[";
    for (int i = 0; i < n; i++) {
        cout << arr[i] << ",";
    }
    cout << "]";
    return 0;
}
